# [doc = " The M-909 multi-nodule path: manifest-driven project loading, nodule linking, and end-to-end"] # [doc = " execution. See [`run`]'s doc for the full six-step model. `opts` selects the interpreter's depth"] # [doc = " budget ([`interpreter_for`] — RFC-0041 §5). Steps 1-3 (parse → dedup/use-resolve/cycle-guard →"] # [doc = " assemble → [`check_phylum`]) are the shared [`assemble_and_check_phylum`] seam (M-1024) — the same"] # [doc = " front half `myc check`'s [`check_project`] runs, so the two commands resolve cross-nodule"] # [doc = " references identically and diverge only here, after assembly."] fn run_multi_nodule (sources : & [PathBuf] , project_dir : & Path , opts : & RunOptions ,) -> Result < RunReport , Report > { let (phylum_env , parsed) = assemble_and_check_phylum (sources , project_dir) ? ; const ENTRY : & str = "main" ; let entry_path = find_entry_nodule (& phylum_env , & parsed) ? ; let entry_rel = parsed . iter () . find (| (_ , n) | & n . path == entry_path) . map (| (rel , _) | rel . clone ()) . unwrap_or_else (| | entry_path . 0 . join (".")) ; let merged = phylum_env . link () . map_err (| ce | { Report :: new ("myc-run-nodule-fn-collision" , ce . message , 65) . help ("rename one of the conflicting declarations — cross-nodule name collisions are not \
             yet disambiguated (v0; a future project-scoped linker will lift this, M-982)" ,) }) ? ; let node = elaborate (& merged , ENTRY) . map_err (| ee | { Report :: new ("myc-run-residual" , ee . to_string () , 70) . at (entry_rel . clone ()) . help ("the program uses a construct outside the evaluation-complete fragment \
                 (RFC-0007 §4.6); `myc run` v0 executes only the elaborated fragment" ,) }) ? ; let interp = interpreter_for (opts) ; let value = interp . eval (& node) . map_err (| ee | { Report :: new ("myc-run-eval" , ee . to_string () , 65) . at (entry_rel . clone ()) . help ("the program failed during interpreted evaluation — see the error above") }) ? ; Ok (RunReport { source : entry_rel , entry : ENTRY . to_owned () , rendered : format ! ("{value:?}") , }) }

# [doc = " The single nodule declaring a nullary `main`, or an explicit refusal — zero candidates is"] # [doc = " `myc-run-no-entry`; more than one is `myc-run-entry-ambiguous` (never guesses between them, G2)."] fn find_entry_nodule < 'a > (phylum_env : & 'a PhylumEnv , parsed : & [(String , Nodule)] ,) -> Result < & 'a NoduleAstPath , Report > { let candidates : Vec < & NoduleAstPath > = phylum_env . nodules . iter () . filter (| (_ , env) | env . fn_decl ("main") . is_some ()) . map (| (path , _) | path) . collect () ; match candidates . as_slice () { [] => { let nodules : Vec < String > = parsed . iter () . map (| (_ , n) | nodule_path_string (& n . path)) . collect () ; Err (Report :: new ("myc-run-no-entry" , format ! ("no nodule declares a nullary `main` — v0 `myc run` executes `main`; nodules \
                     in this project: {}" , nodules . join (", ")) , 65 ,) . help ("declare a nullary `fn main() => …` in exactly one nodule of the project")) } [only] => Ok (only) , many => { let names : Vec < String > = many . iter () . map (| p | nodule_path_string (p)) . collect () ; Err (Report :: new ("myc-run-entry-ambiguous" , format ! ("more than one nodule declares a nullary `main` ({}) — v0 `myc run` needs a \
                     single, unambiguous entry" , names . join (", ")) , 65 ,) . help ("keep a nullary `main` in exactly one nodule of the project")) } } }

# [doc = " The scaffolded starter nodule for `name`."] fn scaffold_nodule (name : & str) -> String { format ! ("// nodule: {name}
\
         // @summary: {name} — scaffolded by `myc init`; replace with your own definitions.
\
         nodule {name};
\

\
         fn answer() => Binary{{8}} =
  \
         0b0010_1010;
") }
